    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    1,
    'No Equipment Needed - 1w 4x/wk',
    'bodyweight',
    4,
    60,
    ARRAY['Build functional strength', 'Improve body control']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'No Equipment Needed'
ON CONFLICT DO NOTHING;

