", "primary_muscle": "Rectus Abdominis", "secondary_muscles": ["Obliques", "Hip Flexors"], "difficulty": "beginner", "form_cue": "Back flat on floor, extend opposite arm and leg slowly", "substitution": "Bird Dog"}, {"name": "Bicycle Crunch", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 20, "rest_seconds": 30, "weight_guidance": "Bodyweight", "equipment": "Bodyweight", "body_part": "Core", "primary_muscle": "Obliques", "secondary_muscles": ["Rectus Abdominis", "Hip Flexors"], "difficulty": "beginner", "form_cue": "Twist elbow to opposite knee, slow and controlled", "substitution": "Crunch"}, {"name": "Plank", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 1, "rest_seconds": 30, "weight_guidance": "Hold 45 seconds", "equipment": "Bodyweight", "body_part": "Core", "primary_muscle": "Rectus Abdominis", "secondary_muscles": ["Obliques", "Shoulders"], "difficulty": "beginner", "form_cue": "Straight line, no sagging or piking", "substitution": "Forearm Plank"}, {"name": "Leg Raise", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 12, "rest_seconds": 30, "weight_guidance": "Bodyweight", "equipment": "Bodyweight", "body_part": "Core", "primary_muscle": "Rectus Abdominis", "secondary_muscles": ["Hip Flexors"], "difficulty": "intermediate", "form_cue": "Legs straight, lower slowly, dont let back arch", "substitution": "Bent-Knee Leg Raise"}, {"name": "Flutter Kick", "exercise_library_id": null, "in_library": false, "sets": 3, "reps": 20, "rest_seconds": 30, "weight_guidance": "Bodyweight", "equipment": "Bodyweight", "body_part": "Core", "primary_muscle": "Rectus Abdominis", "secondary_muscles": ["Hip Flexors", "Obliques"], "difficulty": "beginner", "form_cue": "Small kicks, lower back stays pressed to floor", "substitution": "Dead Bug"}]}]'::jsonb,
